sql:
SELECT flag_description
FROM flags
WHERE flag_id = 1;

SELECT name, title
FROM contact_details
ORDER BY title ASC;

SELECT COUNT(DISTINCT field_id) AS unique_stem_fields
FROM fields_of_study
WHERE field_category = 'STEM';

SELECT field_category, COUNT(DISTINCT field_name) AS unique_fields
FROM fields_of_study
GROUP BY field_category;

SELECT COUNT(*) AS contact_count, institution
FROM contact_details
WHERE institution = 'Global Education Institute';

